      client.getFreeBikeStatus()
    }
  }

  @Test
  fun bcycle() = runTest {
    val client = GbfsV1Client(createMockEngine("bcycle"))

    val manifest = client.getSystemManifest("gbfs.json")
    val service = manifest.data.getService("en")

    context(service) {
